#include <linux/types.h>
#include <linux/bpf.h>
#include <bpf/bpf_helpers.h>
#include <bpf/bpf_tracing.h>

struct {
    __uint(type, BPF_MAP_TYPE_ARRAY);
    __uint(max_entries, 1);
    __type(key, __u32);
    __type(value, __u64);
} counter SEC(".maps");

struct {
    __uint(type, BPF_MAP_TYPE_ARRAY);
    __uint(max_entries, 1);
    __type(key, __u32);
    __type(value, __u32); /* target tgid */
} cfg SEC(".maps");

const char expected_str[] = "ok";

#define bpf_strncmp(s, len, t) ({ \\
    int _i, _r = 0; \\
    for (_i = 0; _i < (len); _i++) { \\
        unsigned char _c1 = ((unsigned char *)(s))[_i]; \\
        unsigned char _c2 = ((unsigned char *)(t))[_i]; \\
        if (_c1 != _c2) { _r = (int)(_c1 - _c2); break; } \\
        if (!_c1) { _r = 0; break; } \\
    } \\
    _r; \\
})

SEC("tracepoint/syscalls/sys_enter_openat")
int helper_arg_decrease(struct trace_event_raw_sys_enter *ctx)
{
    __u32 key = 0;
    __u64 *val = bpf_map_lookup_elem(&counter, &key);
    __u32 *target_tgid = bpf_map_lookup_elem(&cfg, &key);
    const char s1[] = "ok";
    long ret;

    if (!val)
        return 0;

    if (target_tgid && *target_tgid) {
        __u32 tgid = (__u32)(bpf_get_current_pid_tgid() >> 32);
        if (tgid != *target_tgid)
            return 0;
    }
    /* Crutial block */
    ret = bpf_strncmp(s1, sizeof(s1), expected_str);
    /* Crutial block end */
    if (ret == 0)
        (*val)++;

    return 0;
}

char LICENSE[] SEC("license") = "GPL";

